import os
from pathlib import Path

def find_large_files(dirpath, threshold):
    files = []
    for f in Path(dirpath).glob('**/*'):
        if f.is_file() and f.stat().st_size > threshold:
            files.append(f)
    return files

def remove_large_files(files):
    for f in files:
        try:
            filepath = str(f)
            os.chmod(filepath, 0o777)
            os.remove(filepath)
        except OSError:
            pass

